body:
The following index definition example uses the
[Sample Mflix Dataset](sample-mflix) collection. The index
definition example indexes only the `email` field as the
`autocomplete` type to support search-as-you-type queries against that
field using the [autocomplete](autocomplete-ref) operator. The
index definition specifies the following:

- Use the [keyword analyzer](ref-keyword-analyzer) analyzer to
  accept a string or array of strings as a parameter and index
  them as a single term (token).

- Use the [nGram](nGram-tokenizer-ref) tokenizer to
  tokenize text into chunks, or "n-grams", of given sizes.

- Index a minimum of `3` characters per indexed sequence.

- Index a maximum of `15` characters per indexed sequence.

- Include diacritic marks in the index and query text.

You can also use the `uaxUrlEmail` tokenizer to tokenizes
URL (Uniform Resource Locator)s and email addresses. To learn more, see
[uaxUrlEmail](uaxUrlEmail-tokenizer-ref).

```cpp
#include <iostream>

#include <bsoncxx/builder/basic/document.hpp>
#include <bsoncxx/json.hpp>
#include <mongocxx/client.hpp>
#include <mongocxx/instance.hpp>
#include <mongocxx/uri.hpp>
#include <mongocxx/search_index.hpp>

using bsoncxx::builder::basic::kvp;
using bsoncxx::builder::basic::make_document;

int main(){

    mongocxx::instance instance;
    mongocxx::uri uri("<connection-string>");
    mongocxx::client client(uri);

    auto db = client["sample_mflix"];
    auto collection = db["users"];

    // instantiate a ``mongocxx::search_index_view`` on your collection
    auto siv = collection.search_indexes();

    {
        auto name = "default";
        auto definition = make_document(
            kvp("mappings", make_document(
                kvp("dynamic", true),
                kvp("fields", make_document(
                    kvp("email", make_document(
                        kvp("type", "autocomplete"),
                        kvp("analyzer", "lucene.keyword"),
                        kvp("tokenization", "nGram"),
                        kvp("minGrams", 3),
                        kvp("maxGrams", 15),
                        kvp("foldDiacritics", false)
                    ))
                ))
            ))
        );

        auto model = mongocxx::search_index_model(name, definition.view());
        // Create the search index
        auto result = siv.create_one(model);
        if (result) {
            std::cout << "New index name: " << *result << std::endl;
        } else {
            std::cout << "Failed to create search index." << std::endl;
        }
    }
}
}

```

